@import '../../utils/focus-ring.css';
@import '../../utils/interaction-fill.css';
@import '../../utils/control-inactive.css';
@import '../../utils/control-density.css';
@import '../../utils/control-width.css';

:host {
  display: inline-flex;
  outline: none;
  --ds-button-unfilled-fg: var(--color-foreground-secondary);
  --ds-button-unfilled-fg-active: var(--color-foreground-primary);
  --ds-button-unfilled-dot-ring: var(--color-background-secondary);
  --ds-button-unfilled-border: var(--color-border-secondary);
}

/* Icon-only: fixed square from density height (hug). Fill stretches the hit target. */
:host(.button-unfilled-host--icon.ds-control-width--hug) {
  width: var(--ds-control-height, var(--dimension-size-400));
  height: var(--ds-control-height, var(--dimension-size-400));
  min-width: var(--ds-control-height, var(--dimension-size-400));
  min-height: var(--ds-control-height, var(--dimension-size-400));
}

:host(.button-unfilled-host--icon.ds-control-width--fill) {
  height: var(--ds-control-height, var(--dimension-size-400));
  min-height: var(--ds-control-height, var(--dimension-size-400));
}

:host(.ds-control-width--fill) .button-unfilled {
  width: 100%;
}

.button-unfilled {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  box-sizing: border-box;
  height: var(--ds-control-height, var(--dimension-size-400));
  padding: 0 var(--ds-control-padding-inline, var(--dimension-space-075));
  gap: var(--ds-control-gap, var(--dimension-space-050));
  background: transparent;
  border: none;
  border-radius: var(--ds-control-radius, var(--dimension-radius-025));
  color: var(--ds-button-unfilled-fg);
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
  overflow: hidden;
  transition: color var(--effect-motion-short-2);
  /* Hover/press/selected fill: `.ds-interaction-fill` (+ `--selected` / `--on-*`).
     Active always promotes foreground to primary (toggle mode). */
}

.button-unfilled--icon {
  width: 100%;
  height: 100%;
  padding: 0;
}

.button-unfilled--active {
  color: var(--ds-button-unfilled-fg-active);
}

/* Inset stroke via interaction-fill ::after (above selected / hover washes). */
.button-unfilled--bordered {
  --ds-interaction-border-width: var(--dimension-stroke-width-012);
  --ds-interaction-border-color: var(--ds-button-unfilled-border);
}

/* Fallback if interaction-fill is omitted (should be rare — prefer keep the util class). */
.button-unfilled--bordered:not(.ds-interaction-fill) {
  box-shadow: inset 0 0 0 var(--ds-interaction-border-width) var(--ds-interaction-border-color);
}

/* Inactive: `.ds-control-inactive` (25% opacity). */

/* Foreground / chrome tokens per surface — interaction tokens come from util `--on-*`. */
.button-unfilled--contrast-medium {
  --ds-button-unfilled-fg: var(--color-foreground-on-medium-background-secondary);
  --ds-button-unfilled-fg-active: var(--color-foreground-on-medium-background-primary);
  --ds-button-unfilled-dot-ring: var(--color-background-medium-neutral);
  --ds-button-unfilled-border: var(--color-border-on-medium-background-secondary);
}

.button-unfilled--contrast-bold {
  --ds-button-unfilled-fg: var(--color-foreground-on-bold-background-secondary);
  --ds-button-unfilled-fg-active: var(--color-foreground-on-bold-background-primary);
  --ds-button-unfilled-dot-ring: var(--color-background-bold-neutral);
  --ds-button-unfilled-border: var(--color-border-on-bold-background-secondary);
}

.button-unfilled--contrast-strong {
  --ds-button-unfilled-fg: var(--color-foreground-on-strong-background-secondary);
  --ds-button-unfilled-fg-active: var(--color-foreground-on-strong-background-primary);
  --ds-button-unfilled-dot-ring: var(--color-background-strong-neutral);
  --ds-button-unfilled-border: var(--color-border-on-strong-background-secondary);
}

.button-unfilled--on-always-dark {
  --ds-button-unfilled-fg: var(--color-always-dark-foreground-secondary);
  --ds-button-unfilled-fg-active: var(--color-always-dark-foreground-primary);
  --ds-button-unfilled-dot-ring: var(--color-always-dark-background);
  --ds-button-unfilled-border: var(--color-always-dark-border-secondary);
}

.button-unfilled--on-navigation {
  --ds-button-unfilled-fg: var(--color-navigation-foreground-secondary);
  --ds-button-unfilled-fg-active: var(--color-navigation-foreground-primary);
  --ds-button-unfilled-dot-ring: var(--color-navigation-background);
  --ds-button-unfilled-border: var(--color-navigation-border-secondary);
}

/*
 * After surface ring defaults: selected fill remaps the knock-out to the active
 * wash so the badge halo matches the selected background.
 */
.button-unfilled.ds-interaction-fill--selected {
  --ds-button-unfilled-dot-ring: var(--ds-interaction-active);
}

.button-unfilled__icon-wrap {
  position: relative;
  width: var(--ds-control-icon, var(--dimension-iconography-md));
  height: var(--ds-control-icon, var(--dimension-iconography-md));
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  z-index: 2;
}

.button-unfilled__label {
  position: relative;
  z-index: 2;
  line-height: 0;
  padding: 0 var(--ds-control-label-inset, var(--dimension-space-025));
  white-space: nowrap;
  flex-shrink: 0;
  min-width: 0;
}

.button-unfilled__dot {
  position: absolute;
  top: 0;
  right: 0;
  z-index: 2;
  pointer-events: none;
}

import { Component, Element, Event, EventEmitter, h, Host, Method, Prop } from '@stencil/core';
import { controlWidthClass, CONTROL_TEXT_VARIANT, type ControlWidth } from '../../utils';

export type ButtonUnfilledOnBackgroundContrast = 'default' | 'medium' | 'bold' | 'strong';

export type ButtonUnfilledBackground = 'always-dark' | 'navigation';

export type ButtonUnfilledVariant = 'icon' | 'label' | 'icon-label';

export type ButtonUnfilledSize = 'md' | 'sm' | 'xs';

export type ButtonUnfilledWidth = ControlWidth;

/**
 * `ds-icon` size prop matching control-density icon metrics
 * (md→20 / sm→16 / xs→12 via `--dimension-iconography-*`).
 */
const ICON_SIZE: Record<ButtonUnfilledSize, 'md' | 'sm' | 'xs'> = {
  md: 'md',
  sm: 'sm',
  xs: 'xs',
};

@Component({
  tag: 'ds-button-unfilled',
  styleUrl: 'ButtonUnfilled.css',
  scoped: true,
})
export class ButtonUnfilled {
  @Element() el!: HTMLElement;

  /**
   * Content layout. Default is label-only; pass `icon` for icon-only chrome
   * (nav / tool rails) or `icon-label` for leading icon + text.
   */
  @Prop() variant: ButtonUnfilledVariant = 'label';

  /** Control density (height, padding, icon, type). */
  @Prop() size: ButtonUnfilledSize = 'md';

  /** Width fit — hug content (default) or fill the parent. */
  @Prop() width: ButtonUnfilledWidth = 'hug';

  /** Visible text for `label` / `icon-label` variants. */
  @Prop() label: string = '';

  /** Icon name passed to <ds-icon> for `icon` / `icon-label` variants. */
  @Prop() icon: string = '';

  /** Active/selected visual state. Always promotes foreground to primary. */
  @Prop() isActive: boolean = false;

  /**
   * When active, render the selected interaction fill.
   * Default `true` for general UI. Shell chrome (nav / tool rails) should pass
   * `false` so selection is foreground-only (primary color, no fill).
   */
  @Prop() activeFill: boolean = true;

  /** Show a 1px secondary inset border. Default on; shell chrome can pass `false`. */
  @Prop() hasBorder: boolean = true;

  /** Show a notification dot at the top-right of the icon zone (icon variant only). */
  @Prop() dot: boolean = false;

  /** Disables interaction. */
  @Prop() isInactive: boolean = false;

  /** Native button type. */
  @Prop() type: 'button' | 'submit' | 'reset' = 'button';

  /**
   * Foreground and interaction tokens when the button sits on a contrasting parent
   * background (default, medium, bold, or strong).
   */
  @Prop({ attribute: 'on-background-contrast' })
  backgroundContrast?: ButtonUnfilledOnBackgroundContrast;

  /** Parent surface context for navigation and always-dark chrome. */
  @Prop() background: ButtonUnfilledBackground | undefined;

  @Prop({ attribute: 'aria-label' }) ariaLabel: string | undefined;
  @Prop() controls: string | undefined;
  @Prop() expanded: boolean | undefined;
  @Prop() haspopup: string | undefined;
  @Prop() pressed: boolean | undefined;

  /**
   * Native `tabindex` for roving keyboard groups in shell chrome.
   * Omit for the default button tab stop (`0`).
   */
  @Prop({ attribute: 'tab-index' }) focusTabIndex?: number;

  @Event() dsClick!: EventEmitter<MouseEvent>;
  @Event() dsChange!: EventEmitter<boolean>;

  private buttonEl: HTMLButtonElement | null = null;

  @Method()
  async setFocus() {
    this.buttonEl?.focus();
  }

  private handleClick = (event: MouseEvent) => {
    if (this.isInactive) return;
    this.dsClick.emit(event);
    this.dsChange.emit(!this.isActive);
  };

  private effectiveContrast(): ButtonUnfilledOnBackgroundContrast {
    return this.backgroundContrast ?? 'default';
  }

  private get showIcon(): boolean {
    return this.variant === 'icon' || this.variant === 'icon-label';
  }

  private get showLabel(): boolean {
    return this.variant === 'label' || this.variant === 'icon-label';
  }

  private get showDot(): boolean {
    return this.variant === 'icon' && this.dot;
  }

  /** Knock-out ring: selected fill → active wash; otherwise surface token. */
  private get dotRing(): string {
    if (this.isActive && this.activeFill) {
      return 'var(--ds-interaction-active)';
    }
    return 'var(--ds-button-unfilled-dot-ring)';
  }

  private get accessibleName(): string | undefined {
    if (this.ariaLabel) return this.ariaLabel;
    if (this.showLabel && this.label) return undefined;
    if (this.variant === 'icon') return this.icon || 'action';
    return this.label || 'action';
  }

  render() {
    const bg = this.background;
    const contrast = this.effectiveContrast();
    const textVariant = CONTROL_TEXT_VARIANT[this.size];
    const iconSize = ICON_SIZE[this.size];

    const cls: Record<string, boolean> = {
      'button-unfilled': true,
      'ds-focus-ring-inset': true,
      'ds-interaction-fill': true,
      'ds-interaction-fill--selected': this.isActive && this.activeFill && !this.isInactive,
      'ds-interaction-fill--on-medium': contrast === 'medium',
      'ds-interaction-fill--on-bold': contrast === 'bold',
      'ds-interaction-fill--on-strong': contrast === 'strong',
      'ds-interaction-fill--on-always-dark': bg === 'always-dark',
      'ds-interaction-fill--on-navigation': bg === 'navigation',
      'button-unfilled--active': this.isActive,
      'button-unfilled--bordered': this.hasBorder,
      'ds-control-inactive': this.isInactive,
      'ds-control--md': this.size === 'md',
      'ds-control--sm': this.size === 'sm',
      'ds-control--xs': this.size === 'xs',
      'button-unfilled--icon': this.variant === 'icon',
      'button-unfilled--label': this.variant === 'label',
      'button-unfilled--icon-label': this.variant === 'icon-label',
      'button-unfilled--contrast-medium': contrast === 'medium',
      'button-unfilled--contrast-bold': contrast === 'bold',
      'button-unfilled--contrast-strong': contrast === 'strong',
      'button-unfilled--on-always-dark': bg === 'always-dark',
      'button-unfilled--on-navigation': bg === 'navigation',
    };

    return (
      <Host
        class={{
          'button-unfilled-host': true,
          'button-unfilled-host--icon': this.variant === 'icon',
          'ds-control--md': this.size === 'md',
          'ds-control--sm': this.size === 'sm',
          'ds-control--xs': this.size === 'xs',
          ...controlWidthClass(this.width),
        }}
        tabIndex={-1}
      >
        <button
          ref={el => {
            this.buttonEl = el ?? null;
          }}
          type={this.type}
          class={cls}
          disabled={this.isInactive}
          tabIndex={this.focusTabIndex ?? 0}
          aria-label={this.accessibleName}
          aria-controls={this.controls}
          aria-expanded={this.expanded === undefined ? undefined : String(this.expanded)}
          aria-haspopup={this.haspopup}
          aria-pressed={this.pressed === undefined ? undefined : String(this.pressed)}
          onClick={this.handleClick}
        >
          {this.showIcon && (
            <span class="button-unfilled__icon-wrap ds-interaction-fill__content">
              <ds-icon name={this.icon} size={iconSize} color="inherit" />
              {this.showDot && (
                <ds-badge
                  class="button-unfilled__dot"
                  variant="dot"
                  background={this.dotRing}
                  label=""
                  aria-hidden="true"
                />
              )}
            </span>
          )}
          {this.showLabel && (
            <span class="button-unfilled__label ds-interaction-fill__content">
              <ds-text as="span" variant={textVariant} emphasis color="inherit">
                {this.label}
              </ds-text>
            </span>
          )}
        </button>
      </Host>
    );
  }
}
